 60→export function fieldsByTheme(fields: SearchField[]): ThemeGroup[] {
 61→  // Group fields by theme
 62→  const grouped = new Map<Theme, SearchField[]>()
 63→  for (const f of fields) {
 64→    const existing = grouped.get(f.theme)
