143→export function parseUrlToFilters(
144→  params: URLSearchParams,
145→  fields: SearchField[],
146→): Record<string, unknown> {
147→  const filters: Record<string, unknown> = {}
148→  const fieldMap = new Map(fields.map((f) => [f.name, f]))
149→
150→  // Handle legacy ?q= param — maps to the "name" field
151→  const q = params.get('q')
152→  if (q && !params.has('name')) {
153→    filters.name = { query: q }
154→  }
155→
156→  for (const [key, raw] of params.entries()) {
157→    if (key === 'q') continue
158→    const field = fieldMap.get(key)
159→    if (!field) continue
160→
161→    if (field.__typename === 'TextSearchField') {
162→      filters[key] = { query: raw }
163→    } else if (field.__typename === 'BinarySearchField') {
164→      filters[key] = { value: raw }
165→    } else if (field.__typename === 'ChoiceSearchField') {
166→      if (field.maxSelections === 1) {
167→        filters[key] = { value: raw }
168→      } else {
169→        filters[key] = { values: raw.split(',').filter(Boolean) }
170→      }
171→    } else if (field.__typename === 'NumericalSearchField') {
172→      const num = Number(raw)
173→      if (!isNaN(num)) {
174→        filters[key] = { value: num }
175→      }
176→    } else if (field.__typename === 'GeoSearchField') {
177→      const parts = raw.split(',')
178→      if (parts.length === 3) {
179→        const [lat, lng, r] = parts.map(Number)
180→        if (!isNaN(lat) && !isNaN(lng) && !isNaN(r)) {
181→          filters[key] = { latitude: lat, longitude: lng, radiusMiles: r }
182→        }
183→      }
184→    } else if (field.__typename === 'NumericalRangeSearchField') {
185→      if (raw.includes(',')) {
186→        const [minStr, maxStr] = raw.split(',')
187→        const minVal = Number(minStr)
188→        const maxVal = Number(maxStr)
189→        if (!isNaN(minVal) && !isNaN(maxVal)) {
190→          filters[key] = { min: minVal, max: maxVal }
191→        }
192→      } else {
193→        const num = Number(raw)
194→        if (!isNaN(num)) {
195→          filters[key] = { max: num }
196→        }
197→      }
198→    }
199→  }
200→
201→  return filters
202→}
